/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(InventJournalTransfer, InventJournalTable), FormDataSourceEventType::Activated)]
public static void InventJournalTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    if(ETGACFParameters::find().EnablefinancialdimensionVertical)
    {
        FormRun            formRun        = sender.formRun();
        FormDataSource     formDS         = formRun.dataSource(formDataSourceStr(InventJournalTransfer,InventJournalTable));
        InventJournalTable invJournalTabl = formDS.cursor() as InventJournalTable;

        FormControl  addbutton  = formRun.control(formRun.controlId(FormControlstr(InventJournalTransfer, NewLine)));

        FormControl  addinvoicelines  = formRun.control(formRun.controlId(FormControlstr(InventJournalTransfer, ETGPurchCopyingCustom)));

        FormControl  dimensionEntryControlTo  = formRun.control(formRun.controlId(FormControlstr(InventJournalTransfer,DimensionEntryControlTo)));

        FormControl ctrl = formRun.design().controlName("InventJournalTrans_ETGToDefaultDimension");


        if(invJournalTabl && InventJournalName::find(invJournalTabl.JournalNameId).ETGTransferJournalFDChange == NoYes::Yes)
        {

            if (ctrl)
            {
                ctrl.enabled(true);
                ctrl.allowEdit(true);
                ctrl.visible(true);
            }
            if(addbutton)
            {
                addbutton.enabled(false);
                addinvoicelines.enabled(true);

            }
            if(invJournalTabl.Posted)
            {
                addbutton.enabled(false);
                addinvoicelines.enabled(false);
            }
            if(dimensionEntryControlTo)
            {
                dimensionEntryControlTo.enabled(false);
                dimensionEntryControlTo.visible(false);
            }
        }
        else
        {
            addbutton.enabled(true);
            addinvoicelines.enabled(false);
            dimensionEntryControlTo.enabled(true);
            dimensionEntryControlTo.visible(true);
            ctrl.visible(false);
            ctrl.enabled(false);
        }
    }
}
